class Solution:
    def stringIndices(self, wordsContainer, wordsQuery):
        ans = []
        for q in wordsQuery:
            best_idx = 0
            best_len = -1
            best_len_val = len(wordsContainer[0])
            for i, w in enumerate(wordsContainer):
                # compute common suffix length
                common = 0
                for a, b in zip(reversed(q), reversed(w)):
                    if a == b:
                        common += 1
                    else:
                        break
                if (common > best_len or
                        (common == best_len and len(w) < best_len_val) or
                        (common == best_len and len(w) == best_len_val and i < best_idx)):
                    best_len = common
                    best_idx = i
                    best_len_val = len(w)
            ans.append(best_idx)
        return ans

