class Solution:
    def stringIndices(self, wordsContainer, wordsQuery):
        # Trie on reversed strings
        # Each node: children dict, best = (length, index) of best container
        trie = {}
        # best at root = shortest container
        def best_cmp(cur, length, idx):
            if cur is None:
                return (length, idx)
            cl, ci = cur
            if length < cl or (length == cl and idx < ci):
                return (length, idx)
            return cur

        root_best = None
        for i, w in enumerate(wordsContainer):
            root_best = best_cmp(root_best, len(w), i)

        # Build trie
        node_best = {}  # node_id -> (length, idx)
        children = {}   # node_id -> {char: node_id}
        node_count = [1]
        children[0] = {}
        node_best[0] = root_best

        for i, w in enumerate(wordsContainer):
            cur = 0
            for c in reversed(w):
                if c not in children[cur]:
                    nid = node_count[0]
                    node_count[0] += 1
                    children[nid] = {}
                    node_best[nid] = None
                    children[cur][c] = nid
                cur = children[cur][c]
                node_best[cur] = best_cmp(node_best[cur], len(w), i)
            # Ensure nodes without their own container use parent's best
            # (already handled since we propagate from root)

        # For nodes that don't have any container ending at/below them,
        # they should inherit the root best. We handle this by initialising
        # every node with root_best and updating only if better.
        # Reinit: set every node's best to root_best initially
        for nid in node_best:
            if node_best[nid] is None:
                node_best[nid] = root_best

        ans = []
        for q in wordsQuery:
            cur = 0
            for c in reversed(q):
                if c in children[cur]:
                    cur = children[cur][c]
                else:
                    break
            ans.append(node_best[cur][1])
        return ans

