var stringIndices = function(wordsContainer, wordsQuery) {
    // Build trie on reversed container strings
    const children = [{}];
    const nodeBest = [null];  // null until a word passes through this node

    function bestCmp(cur, length, idx) {
        if (cur === null) return [length, idx];
        if (length < cur[0] || (length === cur[0] && idx < cur[1])) return [length, idx];
        return cur;
    }

    let rootBest = null;
    for (let i = 0; i < wordsContainer.length; i++) {
        rootBest = bestCmp(rootBest, wordsContainer[i].length, i);
    }
    nodeBest[0] = rootBest;

    for (let i = 0; i < wordsContainer.length; i++) {
        const w = wordsContainer[i];
        let cur = 0;
        for (let j = w.length - 1; j >= 0; j--) {
            const c = w[j];
            if (!(c in children[cur])) {
                const nid = children.length;
                children.push({});
                nodeBest.push(null);  // start null; filled by insertions
                children[cur][c] = nid;
            }
            cur = children[cur][c];
            nodeBest[cur] = bestCmp(nodeBest[cur], w.length, i);
        }
    }
    // Nodes with no container passing through inherit root best
    for (let i = 0; i < nodeBest.length; i++) {
        if (nodeBest[i] === null) nodeBest[i] = rootBest;
    }

    const ans = [];
    for (const q of wordsQuery) {
        let cur = 0;
        for (let j = q.length - 1; j >= 0; j--) {
            const c = q[j];
            if (c in children[cur]) cur = children[cur][c];
            else break;
        }
        ans.push(nodeBest[cur][1]);
    }
    return ans;
};
